-- Enrichment marathon batch: Runn, RunPod, Runway, Rybbit, Rygel, Rytr, s-cart, Safebucket

-- в”Ђв”Ђ Runn в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Resource management and capacity planning software that helps agencies and professional services teams schedule people, track utilization, and forecast project financials in real time.$q$, short_description),
  pricing_model = COALESCE($q$Per-resource seat subscription, minimum 20 seats, monthly or annual billing, with a free trial$q$, pricing_model),
  starting_price = COALESCE($q$$7 per resource per month (Lite plan)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Wellington, New Zealand$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Runn Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$An independent look at Runn's resource planning software, covering seat-based pricing, scheduling and forecasting features, and who it is really built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Runn is a resource management and capacity planning platform founded in 2018 and headquartered in Wellington, New Zealand. The company was built by a remote-first team to replace spreadsheet-based resourcing with a real-time view of who is working on what, helping agencies, consultancies, and other professional services organizations balance workload, forecast utilization, and protect project margins. As of 2026 Runn reports serving 500-plus customers and over 15,000 users across more than 100 countries, with its platform having tracked more than 47 million logged hours, over 53,000 planned projects, and roughly 38,000 resource allocations, figures the company publishes on its own site as usage milestones rather than third-party audited statistics. Runn's core product centers on a visual scheduling grid that shows tentative and confirmed project assignments alongside capacity and availability charts, so managers can spot overbooking or bench time before it becomes a problem. It layers in project financials, letting teams model budgets, billable rates, and forecasted revenue against actual time logged, and it supports skills and tags so resourcing decisions can be filtered by who is qualified for a given role. Runn prices itself on a per-resource seat basis rather than per named user, meaning every person placed on the planner, whether or not they log into the software, counts toward the seat total, and plans start at a 20-resource minimum. The Lite plan is $7 per resource per month and includes scheduling, tentative projects, capacity charts, skills and tags, and project financials. The Standard plan is $11 per resource per month and adds timesheets, five custom fields, third-party integrations, API access, and a 30-day audit log. Runn also offers a free trial that does not require a credit card, letting prospective customers test the scheduling and forecasting workflow before committing to a paid seat count. The product integrates with common project and finance tools and is aimed squarely at teams that need to reconcile people-planning with financial forecasting in one place, distinguishing it from pure timesheet tools or generic project management software. Because pricing scales with headcount rather than software users, Runn tends to suit mid-sized professional services firms with dozens to low hundreds of billable staff rather than very small teams or large enterprises with thousands of resources, where seat costs would compound quickly.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bf5ccccf-0e75-4299-a56e-49f4447411f2';

