INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Visual resource scheduling$q$, $q$A drag-and-drop planner grid shows confirmed and tentative assignments across every project so managers can spot conflicts before they happen.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Capacity and availability charts$q$, $q$Real-time charts surface who is overbooked and who has spare capacity, helping teams rebalance workload proactively.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Project financial forecasting$q$, $q$Tracks budgets, billable rates, and forecasted revenue against actual logged time to protect project margins.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Skills and tags$q$, $q$Tag people by role, skill, or qualification so resourcing decisions can be filtered to the right fit for a project.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Timesheets$q$, $q$Available on the Standard plan, timesheets let teams reconcile planned hours against actual time worked.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Custom fields and API access$q$, $q$Standard plan customers can add custom fields and connect Runn to other systems through the API and integrations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Audit log$q$, $q$A 30-day audit log on the Standard plan gives visibility into changes made across the planner for accountability.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Multi-project, multi-team view$q$, $q$Runn is designed for organizations juggling many concurrent projects and teams rather than single-project tracking.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Resource-seat pricing scales predictably with headcount rather than software logins$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Combines scheduling and financial forecasting in one visual tool instead of separate spreadsheets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Free trial available without requiring a credit card$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Skills and tags make it easy to match the right person to the right project$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Remote-first company with a global customer base across 100-plus countries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Seat-based pricing counts every planned resource, which can raise costs for larger teams even if they rarely log in$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$20-resource minimum makes it less economical for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Timesheets, integrations, and API access are locked behind the higher Standard tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Company size is relatively small, which may mean slower feature velocity than larger competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Primarily built for professional services scheduling, so it is less suited to general project management needs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$What is Runn used for$q$, $q$Runn is used for resource management and capacity planning, helping teams schedule people across projects, forecast utilization, and track project financials in one place.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$How does Runn pricing work$q$, $q$Runn charges per resource seat rather than per software user, with a 20-resource minimum, starting at $7 per resource per month on the Lite plan and $11 per resource per month on the Standard plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Does Runn offer a free trial$q$, $q$Yes, Runn offers a free trial that does not require a credit card to start.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$When was Runn founded$q$, $q$Runn was founded in 2018 and is headquartered in Wellington, New Zealand.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Does Runn include timesheets$q$, $q$Timesheets are included on the Standard plan along with custom fields, integrations, API access, and a 30-day audit log.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Who is Runn built for$q$, $q$Runn is built for agencies, consultancies, and other professional services organizations that need to plan billable staff across multiple concurrent projects.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Does Runn integrate with other tools$q$, $q$Runn's Standard plan includes third-party integrations and API access for connecting to other project and finance systems.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Is Runn cloud-based$q$, $q$Yes, Runn is a cloud-based SaaS platform accessible from any browser.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Agency resource scheduling$q$, $q$Creative and digital agencies use Runn to schedule billable staff across concurrent client projects and avoid overbooking.$q$, $q$Agency operations and resourcing managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Consultancy capacity planning$q$, $q$Consulting firms use Runn to forecast bench time and billable utilization across teams and practice areas.$q$, $q$Consultancy delivery leads and partners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Project financial forecasting$q$, $q$Finance and delivery teams use Runn's project financials to model budgets and forecasted revenue against planned hours.$q$, $q$Project finance managers and PMOs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Free Trial$q$, $q$$0$q$, $q$Trial, no credit card required$q$, NULL, $q$["Full access to evaluate scheduling and forecasting workflows before purchasing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Lite$q$, $q$$7 per resource per month$q$, $q$Monthly or annual, 20 resource minimum$q$, NULL, $q$["Scheduling","Tentative projects","Capacity charts","Skills and tags","Project financials"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$Standard$q$, $q$$11 per resource per month$q$, $q$Monthly or annual, 20 resource minimum$q$, NULL, $q$["Everything in Lite","Timesheets","Five custom fields","Integrations","API access","30-day audit log"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Runn is a resource management and capacity planning tool built for agencies, consultancies, and other professional services businesses that need to schedule people across multiple concurrent projects. Founded in 2018 and based in Wellington, New Zealand, the company positions Runn as a replacement for spreadsheet-based resourcing, combining a visual scheduling grid with project financial forecasting so managers can see workload and budget impact together instead of in separate tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Runn's scheduling grid shows confirmed and tentative project assignments alongside capacity and availability charts, making it easy to identify overbooked staff or unused bench time at a glance. Skills and tags let planners filter resourcing decisions by role or qualification, while project financials track budgets, billable rates, and forecasted revenue against logged time. The Standard plan adds timesheets, custom fields, integrations, API access, and an audit log for teams that need tighter reporting and compliance controls.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf5ccccf-0e75-4299-a56e-49f4447411f2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Runn uses resource seat-based pricing rather than per-user licensing, meaning every person placed on the planner counts toward the seat total regardless of whether they log in. Plans start at a 20-resource minimum, with the Lite plan priced at $7 per resource per month and the Standard plan at $11 per resource per month. A free trial without a required credit card is available for teams that want to test the workflow before purchasing seats.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Per-second GPU billing$q$, $q$Usage is billed down to the second rather than rounded to the hour, so short jobs only pay for time actually used.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Pods for dedicated instances$q$, $q$Dedicated GPU instances for development, training, and long-running jobs across Community and Secure Cloud tiers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Serverless inference workers$q$, $q$Autoscaling GPU workers for inference workloads that scale to zero and bill only for active usage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Multi-node Clusters$q$, $q$Reserved, multi-GPU cluster deployments for distributed training workloads at scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$No egress fees$q$, $q$Data transfer out of RunPod is not charged separately, unlike many hyperscale cloud providers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Wide GPU selection$q$, $q$Access to GPUs ranging from consumer-class RTX cards to data-center H100 and H200 accelerators.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Network and container storage$q$, $q$Separately priced persistent network storage and container disk options for model weights and data.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Global availability$q$, $q$Infrastructure reported to serve developers across 183 countries via a distributed data center footprint.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Per-second billing with no minimum commitments keeps costs predictable for short jobs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Wide range of GPU types from consumer cards to H100 and H200 accelerators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$No egress fees, unlike many hyperscale cloud providers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Serverless tier autoscales inference workers to zero when idle$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Lean, remote-first team has scaled to serve a large global developer base$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Significantly cheaper than large hyperscalers for comparable GPU capacity$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Community Cloud tier trades some security and reliability guarantees for lower price$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Pricing spans multiple product lines, which can be confusing to compare at a glance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Specific GPU model availability can fluctuate with demand$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Requires technical comfort with containers and APIs to get the most out of the platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Support options are more limited without an enterprise-level relationship$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Relatively young company founded in 2022, with less track record than legacy cloud providers$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$What is RunPod used for$q$, $q$RunPod is a GPU cloud platform used for AI and machine learning workloads, including model training, fine-tuning, and inference.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$How is RunPod priced$q$, $q$RunPod uses per-second usage-based billing across its Pods, Serverless, and Clusters products, with rates varying by GPU type and product line.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$When was RunPod founded$q$, $q$RunPod was founded on October 31, 2022 by Zhen Lu and Pardeep Singh.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Where is RunPod headquartered$q$, $q$RunPod is incorporated in Moorestown, New Jersey, and operates as a remote-first team across the US, Canada, Europe, and India.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Does RunPod charge egress fees$q$, $q$No, RunPod advertises no egress fees for data transferred out of the platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$What is the difference between Pods and Serverless on RunPod$q$, $q$Pods are dedicated GPU instances for development and long-running jobs, while Serverless autoscales inference workers based on traffic and bills only for active usage.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Does RunPod offer a free tier$q$, $q$RunPod does not advertise an ongoing free tier; billing is pay-as-you-go per second of GPU usage.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Who is RunPod built for$q$, $q$RunPod is built for developers, startups, and ML teams who need flexible, short-notice GPU access without long-term cloud contracts.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Model training and fine-tuning$q$, $q$ML engineers use RunPod Pods to rent dedicated GPUs for training and fine-tuning models without buying hardware.$q$, $q$ML engineers and researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Scalable AI inference$q$, $q$Teams deploy Serverless endpoints on RunPod to autoscale inference workers for production AI applications.$q$, $q$AI product and platform teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Distributed training clusters$q$, $q$Organizations use RunPod Clusters for multi-node, multi-GPU distributed training of large models.$q$, $q$AI research teams training large-scale models$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Pods (Community Cloud)$q$, $q$From around $0.69 per hour (e.g. RTX 4090)$q$, $q$Per-second usage-based$q$, NULL, $q$["Dedicated GPU instances","Lower-cost shared cloud tier","Suited to development and long-running jobs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Pods (Secure Cloud)$q$, $q$From around $1.39 per hour (e.g. A100 PCIe)$q$, $q$Per-second usage-based$q$, NULL, $q$["Dedicated GPU instances","Higher isolation and reliability tier","Suited to production and sensitive workloads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Serverless$q$, $q$From around $0.69 to $4.55 per hour depending on GPU$q$, $q$Usage-based, billed for active worker time only$q$, NULL, $q$["Autoscaling inference workers","Scales to zero when idle","Marketed as competitively priced against other serverless GPU providers"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$Clusters$q$, $q$From around $1.79 per hour (e.g. A100 SXM)$q$, $q$Per-hour usage-based, reserved options available$q$, NULL, $q$["Multi-node, multi-GPU deployments","Volume discounts for large reserved capacity","Suited to distributed training"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RunPod is a GPU cloud platform focused specifically on AI and machine learning workloads. Founded in October 2022 by Zhen Lu and Pardeep Singh, the company is incorporated in Moorestown, New Jersey, but runs as a remote-first team spread across the US, Canada, Europe, and India. RunPod has grown quickly into a developer-focused alternative to hyperscale clouds, reporting service to hundreds of thousands of developers across nearly 200 countries with a lean employee base.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$RunPod splits its offering into Pods for dedicated GPU instances used in development and long-running jobs, Serverless for autoscaling inference workers billed only on active usage, and Clusters for multi-node distributed training. All three are billed per second with no minimum commitments and no egress fees, and Pods are further split into a lower-cost Community Cloud tier and a more isolated Secure Cloud tier depending on the sensitivity of the workload.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33a2e54d-ea2a-4eac-b6c4-dbd80828337e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RunPod pricing is entirely usage-based rather than subscription-based, with rates varying by GPU model and product line. Example on-demand Pod rates include roughly $2.99 per hour for an H100 SXM and $0.69 per hour for an RTX 4090, while Serverless inference workers range from about $0.69 to $4.55 per hour depending on GPU class. Storage is billed separately, from about $0.05 per GB per month for standard network storage up to $0.14 per GB per month for high-performance storage.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Gen-4 and Gen-4.5 video generation$q$, $q$Runway's flagship models generate video with improved character, location, and object consistency across scenes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$AI image generation$q$, $q$Access to Runway's own image models as well as select third-party models like Nano Banana Pro.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Text to speech and custom voices$q$, $q$Generate narration and custom voice clones for lip sync and text-to-speech on higher-tier plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$4K upscaling$q$, $q$Paid plans can upscale generated video output to 4K resolution.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Browser-based video editor$q$, $q$An integrated editor lets users assemble and edit AI-generated clips without leaving the platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Credit rollover$q$, $q$The Max plan allows unused monthly credits to roll over for up to one additional month.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Asset storage$q$, $q$Plans include tiered cloud storage for generated assets, from 5GB on Free up to 500GB on Pro.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Enterprise controls$q$, $q$The Enterprise plan adds SSO, workspace analytics, custom team configurations, and priority support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Gen-4 models are widely regarded as leading the field for character and scene consistency in AI video$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$One platform provides access to multiple leading AI models, not just Runway's own$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Credit rollover on higher plans reduces waste from unused monthly allowances$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Backed by roughly $860 million in funding, supporting continued model development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Integrated video editor removes the need for a separate editing tool for quick projects$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Frequent model updates keep the platform competitive with fast-moving rivals$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Credit-based pricing can be difficult for new users to estimate against actual usage needs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Advertised monthly prices require annual billing; month-to-month costs more$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Free plan output carries a watermark and offers limited storage$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Higher tiers become expensive quickly for heavy, professional-scale usage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Individual video generations remain limited in length compared to traditional production tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Enterprise pricing is not publicly listed and requires contacting sales$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$What is Runway used for$q$, $q$Runway is used for AI-generated video and image creation, including its Gen-4 models for consistent characters and scenes, plus text-to-speech and video editing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Who founded Runway$q$, $q$Runway was founded in 2018 by Cristobal Valenzuela, Alejandro Matamala, and Anastasis Germanidis, who met at NYU's Tisch School of the Arts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$How does Runway's credit pricing work$q$, $q$Each plan grants a monthly (or one-time, on the Free plan) allowance of credits that are consumed as you generate video, images, or audio, with higher tiers offering more credits and features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Does Runway have a free plan$q$, $q$Yes, Runway offers a Free plan with 125 one-time credits, limited video editor projects, and 5GB of storage, with a watermark on outputs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$What is Runway Gen-4$q$, $q$Gen-4 is Runway's generative AI model family for video and image creation, built for consistent characters, locations, and objects across scenes for professional media production.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$How much does Runway cost per month$q$, $q$Paid plans start at $12 per month billed annually (Standard) and range up to $76 per month billed annually (Max), with an Enterprise plan available at custom pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Where is Runway headquartered$q$, $q$Runway is headquartered in New York City, with additional offices in cities including San Francisco, Seattle, London, and Tel Aviv.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$How much funding has Runway raised$q$, $q$Runway has raised approximately $860 million across seven funding rounds, including a $315 million Series E round closed in February 2026.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Film and video previsualization$q$, $q$Filmmakers use Runway's Gen-4 models to previsualize scenes and generate supplementary footage.$q$, $q$Independent filmmakers and video producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Advertising and marketing creative$q$, $q$Marketing teams use Runway to rapidly generate video and image assets for campaigns without full production shoots.$q$, $q$Marketing and advertising creative teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Social and content creation$q$, $q$Content creators use Runway's image and video generation tools to produce short-form social content.$q$, $q$Social media content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Free$q$, $q$$0$q$, $q$One-time credits, no recurring charge$q$, NULL, $q$["125 one-time credits","Generative video with Gen-4 Turbo","Generative images","Text to speech","3 video editor projects","5GB asset storage","Watermarked output"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Standard$q$, $q$$12 per month billed annually ($15 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["625 credits per month","All AI image and video models","4K upscaling","No watermark"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Pro$q$, $q$$28 per month billed annually ($35 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Standard","2,250 credits per month","Custom voice creation for lip sync and text-to-speech","500GB asset storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Max$q$, $q$$76 per month billed annually ($95 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro","9,500 credits per month","Credit rollover for up to one month","First access to newest models"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$Enterprise$q$, $q$Custom$q$, $q$Custom contract$q$, NULL, $q$["Everything in Max","Custom credit packages","SSO","Workspace analytics","Priority support","Custom team configurations"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Runway is a New York City-based AI research and applied media company founded in 2018 by Cristobal Valenzuela, Alejandro Matamala, and Anastasis Germanidis, who met at NYU's Tisch School of the Arts. The company is best known for its Gen-4 family of AI video and image generation models, which emphasize consistent characters, locations, and objects across scenes for professional film, advertising, and creative production.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Runway's platform combines Gen-4 and Gen-4.5 video generation, AI image generation using Runway's own and select third-party models, text-to-speech, and custom voice creation for lip sync, alongside a browser-based video editor and asset storage. Paid plans add 4K upscaling, watermark-free exports, and, at higher tiers, credit rollover and priority access to new models.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82e23514-860e-4179-aa6e-cc95f88d7372', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Runway uses a freemium, credit-based pricing model. The Free plan grants 125 one-time credits, while paid plans range from $12 per month (Standard, billed annually) up to $76 per month (Max, billed annually), each with a different monthly credit allowance, storage limit, and feature set. An Enterprise plan with custom credit packages and SSO is available for larger teams.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Cookieless tracking$q$, $q$Rybbit tracks site visitors without cookies, anonymizing them with generated display names instead of persistent identifiers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Real-time dashboard$q$, $q$A live analytics dashboard shows visitor activity as it happens across all plans.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Funnel analysis$q$, $q$Built-in funnels help site owners understand conversion drop-off across a visitor journey.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Session replay$q$, $q$Available on the Pro cloud plan and included in the self-hosted build, session replay lets teams watch real user sessions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$EU-hosted cloud infrastructure$q$, $q$Rybbit's hosted service runs from Germany-based infrastructure, supporting GDPR compliance out of the box.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Feature-complete self-hosting$q$, $q$The free, self-hosted AGPL-3 deployment includes the same core features as paid cloud plans, including session replay and funnels.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Multi-site and multi-team support$q$, $q$Standard and Pro cloud plans support multiple websites and team members, with Pro removing caps entirely.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Open-source codebase$q$, $q$Rybbit's full source code is public and licensed under AGPL-3, with the project committed to remaining open source.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Generous free tier covering 3,000 events per month without any cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$No cookies required, simplifying compliance with privacy regulations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Self-hosted version is free and feature-complete rather than a stripped-down demo$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Simpler interface than Google Analytics 4 while offering more depth than minimalist alternatives$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$EU-hosted cloud infrastructure supports GDPR compliance by default$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Affordable paid tiers relative to many analytics competitors$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Very young product, launched in 2025, with a shorter track record than established analytics tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Built and maintained by a very small team, which may limit support capacity at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Advanced features on the hosted plan are gated behind the Pro tier$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Smaller third-party integration ecosystem than long-established analytics platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Rapid early growth means the product and pricing may still change significantly$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$What is Rybbit used for$q$, $q$Rybbit is used as a privacy-first, cookieless web analytics tool, serving as an alternative to Google Analytics for tracking site visitors and conversions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Is Rybbit open source$q$, $q$Yes, Rybbit's full codebase is open source under the AGPL-3 license, and the company states that remaining open source is a permanent core value.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$How much does Rybbit cost$q$, $q$Rybbit offers a free plan for up to 3,000 events per month, with paid cloud plans starting at $13 per month billed annually, or it can be self-hosted for free.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$When was Rybbit founded$q$, $q$Rybbit was built by indie developer Bill Yang and launched publicly on April 15, 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Does Rybbit use cookies$q$, $q$No, Rybbit does not use cookies and instead anonymizes visitors with generated display names.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Is Rybbit GDPR compliant$q$, $q$Rybbit's hosted cloud service runs from infrastructure in Germany, within the EU, which the company positions as GDPR-friendly by default.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Can I self-host Rybbit for free$q$, $q$Yes, Rybbit's self-hosted deployment is free under its AGPL-3 open-source license and is reported to include the same features as the paid cloud plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$How is Rybbit different from Google Analytics$q$, $q$Rybbit is built to be simpler and cookie-free compared to Google Analytics 4, with an emphasis on privacy and an open-source, self-hostable codebase.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Privacy-conscious website analytics$q$, $q$Site owners who want visitor analytics without cookies or personal data collection use Rybbit's cookieless tracking.$q$, $q$Privacy-focused website owners and marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Self-hosted analytics for developers$q$, $q$Developers who want full control over their analytics infrastructure self-host Rybbit's open-source AGPL-3 codebase.$q$, $q$Developers and technical teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Google Analytics replacement$q$, $q$Businesses looking to move off Google Analytics use Rybbit's hosted cloud plans for a simpler, GDPR-friendly alternative.$q$, $q$Small and mid-sized businesses replacing Google Analytics$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["3,000 events per month","1 site"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Standard$q$, $q$$13 per month billed annually ($19 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["100,000 events per month","Up to 5 sites","Up to 3 team members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Pro$q$, $q$$26 per month billed annually ($39 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited sites","Unlimited team members","Session replay","5-year data retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$Self-Hosted$q$, $q$Free$q$, $q$Open source, AGPL-3 license$q$, NULL, $q$["Feature-complete deployment on your own infrastructure","Includes session replay and funnels","No event or site limits imposed by Rybbit"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rybbit is an open-source, cookieless web analytics platform built as a simpler alternative to Google Analytics. It was created by indie developer Bill Yang and launched publicly in April 2025, quickly gaining traction in the open-source community and surpassing 10,000 GitHub stars within its first year. The project is licensed under AGPL-3 and is offered both as a hosted cloud service, run from EU-based infrastructure in Germany, and as a free, feature-complete self-hosted deployment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rybbit does not use cookies and anonymizes visitors with generated display names rather than persistent identifiers, positioning it as GDPR-friendly by default on its EU-hosted cloud plan. The platform includes real-time dashboards and funnel analysis on all tiers, with session replay and extended data retention reserved for the Pro cloud plan, though the self-hosted version includes these advanced features at no cost.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Rybbit's hosted cloud service starts with a Free plan covering 3,000 events per month on one site. The Standard plan is $13 per month billed annually (or $19 monthly) for 100,000 events across up to five sites, and the Pro plan is $26 per month billed annually (or $39 monthly) with unlimited sites, unlimited team members, session replay, and five-year retention. Self-hosting the open-source version is free under the AGPL-3 license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c1b5e9c-512c-48b9-b212-f464f5c0a339', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$UPnP AV MediaServer$q$, $q$Shares audio, video, and photo libraries from a Linux PC to other devices on the local network.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$MediaRenderer support$q$, $q$Rygel can also act as a playback target, receiving media pushed from another UPnP controller device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Automatic transcoding$q$, $q$Converts media on the fly into formats compatible with the requesting client device when needed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Broad device compatibility$q$, $q$Works with DLNA and UPnP clients including smart TVs, PlayStation and Xbox consoles, speakers, and smartphones.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Plug-in architecture$q$, $q$Built around a plug-in mechanism that allows developers to extend or customize server behavior.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Built on GUPnP and Vala$q$, $q$Implemented largely in the Vala language on top of GNOME's GUPnP UPnP library.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Reusable shared libraries$q$, $q$Ships libraries that can be used to build custom plugins, media engines, or standalone renderer and server implementations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Open-source licensing$q$, $q$Distributed under LGPL-2.1-or-later, allowing free use, modification, and redistribution.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Long-running, mature project with development dating back to 2008$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Wide device compatibility across DLNA and UPnP standards$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Automatic transcoding removes the need to manually convert media formats$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Extensible plug-in architecture for developers who want custom behavior$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Integrated into the GNOME desktop ecosystem for Linux users$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$No commercial support, so users rely on community documentation and forums$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Primarily targeted at Linux and GNOME users rather than cross-platform desktop users$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$UPnP and DLNA protocols can be finicky across different consumer device brands$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Setup and troubleshooting require more technical comfort than consumer streaming apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Development activity has varied over the years as a community-maintained project$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$No official mobile app; relies on third-party UPnP or DLNA client apps$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$What is Rygel$q$, $q$Rygel is a free, open-source UPnP AV MediaServer and MediaRenderer for the GNOME desktop that shares media across a home network.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Is Rygel free$q$, $q$Yes, Rygel is completely free and open source under the LGPL-2.1-or-later license.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$What devices work with Rygel$q$, $q$Rygel supports DLNA and UPnP-certified devices including smart TVs, PlayStation and Xbox consoles, DLNA speakers, and smartphones.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Does Rygel transcode media$q$, $q$Yes, Rygel can automatically transcode media on the fly into a format the requesting client device can play.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$When was Rygel first developed$q$, $q$Rygel's first commit dates to April 2008, and it has been developed as part of the GNOME project since.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$What programming language is Rygel written in$q$, $q$Rygel is written largely in the Vala programming language, built on GNOME's GUPnP library.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Is Rygel a company product$q$, $q$No, Rygel is a community-maintained open-source project under the GNOME umbrella, not a commercial company product.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Can developers extend Rygel$q$, $q$Yes, Rygel ships shared libraries and a plug-in architecture that developers can use to build custom plugins, media engines, or standalone servers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Home media streaming$q$, $q$Linux users share personal audio, video, and photo libraries from their PC to smart TVs and other network devices using Rygel.$q$, $q$Linux and GNOME desktop users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Console and TV playback$q$, $q$Households stream media stored on a computer directly to game consoles and DLNA-certified televisions.$q$, $q$Home users with DLNA or UPnP-certified TVs and consoles$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Custom UPnP development$q$, $q$Developers use Rygel's shared libraries to build custom media server plugins or standalone UPnP renderer implementations.$q$, $q$Linux developers building UPnP or DLNA software$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$Open Source$q$, $q$Free$q$, $q$N/A, open source under LGPL-2.1-or-later$q$, NULL, $q$["UPnP AV MediaServer and MediaRenderer functionality","Automatic media transcoding","Plug-in architecture for extensibility","Community support via GNOME project channels"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rygel is a free, open-source home media server maintained as part of the GNOME project, with development dating back to its first commit in April 2008. It implements both a UPnP AV MediaServer and a MediaRenderer, letting Linux users share media libraries across a home network and stream to or from DLNA and UPnP-certified devices. The project is licensed under LGPL-2.1-or-later and written largely in the Vala programming language, built on GNOME's GUPnP library.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rygel allows users to browse and play audio, video, and photo content stored on a PC from devices like smart TVs, game consoles, and DLNA speakers elsewhere on the network. When a client device cannot play a file's original format, Rygel can automatically transcode the media on the fly so playback still succeeds. The project also ships shared libraries that developers can use to build custom Rygel plugins, alternative media engines, or standalone UPnP and DLNA server implementations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Rygel is entirely free and open source under the LGPL-2.1-or-later license, distributed through Linux package repositories and the GNOME GitLab project. There is no commercial edition, subscription, or paid tier; it is community-maintained software rather than a product sold by a company.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1269899d-d0a4-4fea-afe2-1530e36e1f6f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$40-plus content use cases$q$, $q$Predefined templates cover blog content, ad copy, social captions, emails, and many other short-form writing tasks.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Tone-of-voice matching$q$, $q$Paid plans let users match generated content to a specific brand tone of voice.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Multi-language support$q$, $q$The Premium plan supports more than 30 languages for non-English content generation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Plagiarism checking$q$, $q$Built-in plagiarism checks are included on paid plans, with higher monthly allowances on Premium.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Chrome extension$q$, $q$A browser extension lets users generate content directly inside other web apps and forms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Unlimited generation on paid plans$q$, $q$The Unlimited and Premium plans remove the character cap present on the Free plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Custom use cases$q$, $q$Premium subscribers can create custom content use cases tailored to their specific workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Community and priority support$q$, $q$Premium plan subscribers get community access and priority customer support.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Very low starting price compared to many other AI writing tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Free plan available with no credit card required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Wide range of built-in use cases for short-form marketing content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Multi-language support on the top plan for international content needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Unlimited generation on paid plans removes usage anxiety$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Chrome extension makes it usable directly inside other web tools$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Free plan is limited to 10,000 characters per month and one language$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Best suited to short-form content rather than long-form, deeply researched writing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Small company team size may mean slower feature development than larger AI writing competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Annual plans require a 12-month commitment to get the lower rate$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Now operates under parent company Copysmith, which has shifted brand messaging over time$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Output quality for niche or highly technical content may require heavier editing$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$What is Rytr used for$q$, $q$Rytr is used to generate short-form marketing copy, blog content, social captions, and other written content using AI across more than 40 use cases.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Is Rytr free$q$, $q$Rytr offers a Free plan with 10,000 characters per month and no credit card required, alongside paid Unlimited and Premium plans.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$How much does Rytr cost$q$, $q$The Unlimited plan is about $9 per month billed monthly or roughly $7.50 per month billed annually, and the Premium plan is about $29 per month billed monthly or roughly $24.16 per month billed annually.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Who owns Rytr$q$, $q$Rytr was founded in 2021 and acquired by Copysmith in October 2022, after which the products were marketed together under the Copyrytr name.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$How many languages does Rytr support$q$, $q$Rytr's Premium plan supports more than 30 languages, while the Free plan is limited to one language.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Does Rytr check for plagiarism$q$, $q$Yes, paid plans include plagiarism checking, with 50 monthly checks on Unlimited and 100 on Premium.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Can I cancel Rytr anytime$q$, $q$Monthly subscriptions can be canceled anytime, while annual plans carry a 12-month commitment.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Where is Rytr based$q$, $q$Rytr is based in Wilmington, Delaware, United States.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Marketing copywriting$q$, $q$Marketers use Rytr to quickly draft ad copy, social captions, and email content across many predefined use cases.$q$, $q$Marketers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Freelance and agency content$q$, $q$Freelancers and agencies use Rytr's Premium plan to write for multiple brands with different tones of voice.$q$, $q$Freelance writers and content agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Multi-language content creation$q$, $q$Non-English content creators use Rytr's 30-plus language support to generate marketing copy in their target language.$q$, $q$International and multilingual content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Free$q$, $q$$0$q$, $q$Monthly, no credit card required$q$, NULL, $q$["10,000 characters per month","Access to 1 language","No tone-of-voice matching","No plagiarism checks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Unlimited$q$, $q$Around $7.50 per month billed annually (about $9 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited character generation","1 tone-of-voice match","50 plagiarism checks per month","Chrome extension access","Doubled character input limit"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$Premium$q$, $q$Around $24.16 per month billed annually (about $29 per month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited character generation","Multiple tone-of-voice matches","100 plagiarism checks per month","Access to 30-plus languages","Tripled character input limit","Community access, custom use cases, and priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Rytr is an AI writing assistant launched in 2021 that generates short-form marketing and content copy across more than 40 built-in use cases. Based in Wilmington, Delaware, Rytr grew to more than 2 million users before being acquired by Copysmith in October 2022, after which the two products were marketed together under the Copyrytr name while Rytr continued as its own branded tool run by a small team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Rytr covers dozens of predefined content use cases such as blog ideas, ad copy, and social captions, with adjustable tone-of-voice matching and support for more than 30 languages on its top plan. Paid plans add plagiarism checking, a Chrome browser extension, and higher per-generation character limits, while the Premium tier is built specifically for freelancers and agencies writing for multiple brands at once.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ae913412-1cd7-414a-b291-f3e2c6aabc3b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Rytr's Free plan offers 10,000 characters per month with no credit card required. The Unlimited plan runs about $9 per month billed monthly, or roughly $7.50 per month billed annually, and removes the character cap. The Premium plan is about $29 per month billed monthly, or roughly $24.16 per month billed annually, and adds multi-language support, more plagiarism checks, and priority support.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Multi-store and multi-currency support$q$, $q$Run multiple storefronts with different currencies and languages from a single s-cart installation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Product and inventory management$q$, $q$Manage sale price, cost price, promotional pricing, stock quantity, multiple images, and custom attributes per product.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Order and customer management$q$, $q$Track orders end to end and manage customer profiles including multiple shipping addresses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$CMS capabilities$q$, $q$Built-in content management for categories, news posts, and static pages alongside the storefront.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Extensible plugin architecture$q$, $q$Payment gateways, shipping methods, discount rules, and tax calculation are handled through a modular plugin system.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Role-based admin permissions$q$, $q$Admin accounts can be scoped with granular roles and permissions, with audit logging for accountability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Secured API access$q$, $q$A secured API layer supports building mobile apps or third-party integrations on top of the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Reporting and exports$q$, $q$Built-in reporting includes charts and statistics, with export options to CSV and PDF.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Built on the well-established Laravel PHP framework$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Multi-store, multi-language, and multi-currency support built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Extensible plugin architecture for payments, shipping, and tax$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Includes CMS features alongside core e-commerce functionality$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Active GitHub presence with releases distributed via Packagist and SourceForge$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Self-hosted only, requiring server management and technical setup$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$No official managed hosting or vendor support contract$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Smaller plugin and theme ecosystem compared to platforms like WooCommerce or Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Documentation and community support size not comparable to larger commercial platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Requires PHP and Laravel expertise to customize or troubleshoot effectively$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$No disclosed company or funding behind the project, so long-term maintenance depends on community contributors$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$What is s-cart$q$, $q$s-cart is a free, open-source e-commerce platform built on the Laravel PHP framework for running self-hosted online stores.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Is s-cart free to use$q$, $q$Yes, s-cart is completely free and open source with no licensing or subscription cost.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$What technology does s-cart use$q$, $q$s-cart is built on Laravel, with its current stable branch using Laravel 13.x and Tailwind CSS 4, organized in an HMVC plugin architecture.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Does s-cart support multiple languages and currencies$q$, $q$Yes, s-cart includes built-in multi-language and multi-currency support for running international storefronts.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Can s-cart run multiple stores$q$, $q$Yes, s-cart supports multi-store functionality, letting one installation power more than one storefront.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$How do I install s-cart$q$, $q$s-cart can be installed traditionally on a server with PHP and Laravel, or deployed using Docker.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Does s-cart have an API$q$, $q$Yes, s-cart includes a secured API layer for building mobile apps or third-party integrations.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Who maintains s-cart$q$, $q$s-cart is maintained as a community open-source project under the GP247 ecosystem, distributed via GitHub, Packagist, and SourceForge.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Self-hosted online storefronts$q$, $q$Small businesses and individuals use s-cart to launch a self-hosted online store without recurring platform fees.$q$, $q$Small business owners and independent sellers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Developer-customized e-commerce$q$, $q$Developers use s-cart's Laravel codebase and plugin architecture to build heavily customized storefronts.$q$, $q$PHP and Laravel developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Multi-store and marketplace catalogs$q$, $q$Businesses running several related storefronts use s-cart's multi-store and multi-supplier features to manage them from one system.$q$, $q$Multi-brand retailers and marketplace operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$Open Source$q$, $q$Free$q$, $q$N/A, self-hosted open source$q$, NULL, $q$["Full shopping cart and storefront functionality","Multi-store, multi-language, and multi-currency support","CMS, plugin architecture, and secured API access","Community support via GitHub and project documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$s-cart is a free, open-source e-commerce platform built on the Laravel PHP framework and distributed as part of the broader GP247 open-source ecosystem. It is designed to give individuals, small businesses, developers, and students a self-hosted way to run an online store, with the project's stated mission being to stay efficient and friendly for everyone rather than gated behind licensing fees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$s-cart provides a full storefront and shopping cart experience with product, order, and customer management, plus multi-store, multi-language, multi-currency, and multi-supplier support for more complex catalog needs. It includes CMS tools for pages and news, an extensible plugin system for payments, shipping, and tax, role-based admin permissions with audit logging, and a secured API for mobile or third-party integrations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$s-cart is entirely free and open source, with no commercial license, subscription, or vendor support fee. Users self-host the software on their own infrastructure, deploying via traditional installation or Docker, and rely on community documentation and GitHub for support rather than a paid vendor relationship.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('73e6abda-a9cd-47e5-b644-042f92c64ac5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Direct-to-storage file transfer$q$, $q$Files upload and download directly to S3-compatible storage via presigned URLs, bypassing the application server entirely.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$SSO-first authentication$q$, $q$Users authenticate through an organization's existing identity provider via OIDC rather than Safebucket-managed passwords.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Bucket-based access control$q$, $q$Sharing is organized around buckets with explicit membership and owner, contributor, and viewer roles.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Quick and reverse share links$q$, $q$Public share links can be protected with a password, a maximum number of downloads, and a maximum number of views.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Audit logging and activity tracking$q$, $q$Real-time activity logs give visibility into file access and sharing actions for compliance purposes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Multifactor authentication$q$, $q$TOTP-based multifactor authentication adds an extra layer of account security.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$File expiration and trash retention$q$, $q$Files can be set to expire automatically, with a configurable trash retention period before permanent deletion.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Swappable infrastructure components$q$, $q$Storage, database, events, cache, and logging backends can each be independently swapped for different providers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Files never pass through the application server, reducing server load and a potential point of exposure$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Free and open source under the permissive Apache 2.0 license$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Works with a wide range of S3-compatible storage providers, avoiding vendor lock-in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$SSO-first design integrates cleanly with existing identity providers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Granular bucket-based roles and audit logging support compliance needs$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Modern Go and React technology stack that is approachable for developers to extend$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Self-hosted only, requiring organizations to manage their own infrastructure and updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$No founding year, company size, or headquarters publicly disclosed, making it hard to gauge project maturity and backing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$No official managed or hosted SaaS offering documented$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Requires an existing OIDC identity provider and S3-compatible storage to fully set up$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Smaller community and ecosystem compared to established file sharing platforms$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Documentation and support rely on the open-source community rather than a dedicated vendor support team$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$What is Safebucket$q$, $q$Safebucket is an open-source, self-hosted file sharing platform where files upload and download directly to S3-compatible storage instead of passing through the application server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Is Safebucket free$q$, $q$Yes, Safebucket is free and open source under the Apache 2.0 license, deployed on your own infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$What storage providers does Safebucket support$q$, $q$Safebucket supports AWS S3, Google Cloud Storage, MinIO, Wasabi, Backblaze B2, DigitalOcean Spaces, Linode Object Storage, Tencent COS, Alibaba OSS, and other S3-compatible providers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$How does Safebucket handle authentication$q$, $q$Safebucket is SSO-first, authenticating users through an organization's existing identity provider via OIDC rather than managing passwords itself.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Can I password-protect shared files in Safebucket$q$, $q$Yes, quick and reverse share links can be protected with a password, a maximum number of downloads, and a maximum number of views.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$What technology is Safebucket built with$q$, $q$Safebucket is built with a Go backend REST API and a React with TypeScript frontend.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Does Safebucket support multifactor authentication$q$, $q$Yes, Safebucket supports TOTP-based multifactor authentication.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Who is Safebucket built for$q$, $q$Safebucket is built for organizations that already have their own identity provider and object storage infrastructure and want a self-hosted, auditable file sharing layer on top of it.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Self-hosted team file sharing$q$, $q$Organizations deploy Safebucket on their own infrastructure to share files internally without relying on a third-party SaaS vendor.$q$, $q$IT and infrastructure teams at privacy-conscious organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Secure external file sharing$q$, $q$Teams use Safebucket's quick and reverse share links with passwords and download limits to send files to external parties.$q$, $q$Teams sharing files with clients or partners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Compliance-driven file access control$q$, $q$Regulated organizations use Safebucket's bucket-based roles and audit logging to maintain accountable file access records.$q$, $q$Compliance and security teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$Open Source$q$, $q$Free$q$, $q$N/A, self-hosted open source$q$, NULL, $q$["Direct-to-storage file uploads and downloads","SSO-first authentication via OIDC","Bucket-based roles and audit logging","Quick and reverse share links with password and download and view limits","TOTP multifactor authentication","Support for multiple S3-compatible storage providers"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Safebucket is an open-source, self-hosted file sharing platform built so that files never pass through its own application server. Uploads and downloads connect directly to a storage backend via presigned URLs, while the Safebucket server itself only manages metadata, access control, and audit logging. It is licensed under Apache 2.0 and built with a Go backend and a React with TypeScript frontend.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Safebucket is SSO-first, authenticating users through an organization's existing OIDC identity provider rather than managing passwords itself. Sharing is organized around buckets with owner, contributor, and viewer roles, plus quick and reverse share links protected by passwords, download limits, and view limits. The platform also includes real-time activity tracking, audit logs, TOTP multifactor authentication, and configurable file expiration and trash retention.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Safebucket is free and open source under the Apache 2.0 license, distributed via GitHub for self-hosted deployment. There is no vendor-hosted paid tier documented; organizations deploy and run the platform on their own infrastructure, choosing their own storage, database, and event backends.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('991a14b4-c72d-4cf5-87f7-81f3fc26205a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
